args.sparql:
SELECT ?attendance WHERE { 
  ?seriesEdition wdt:P179 wd:Q1363275 .
  {
    ?seriesEdition wdt:P1344 wd:Q650840 ;
                     wdt:P1346 wd:Q334634 .
  } UNION {
    ?seriesEdition wdt:P1344 wd:Q334634 ;
                     wdt:P1346 wd:Q650840 .
  }
  ?game wdt:P361 ?seriesEdition ;
        wdt:P1102 ?attendance .
  FILTER (REGEX(?attendance, "^[0-9,]+$"))
}
ORDER BY DESC(xsd:integer(REPLACE(?attendance, ",", ""))) 
LIMIT 1
